class Solution(object):
    def maximizeSquareHoleArea(self, n, m, hBars, vBars):
        def max_consecutive(bars):
            bars = sorted(bars)
            best = 1
            cur = 1
            for i in range(1, len(bars)):
                if bars[i] == bars[i-1] + 1:
                    cur += 1
                    best = max(best, cur)
                else:
                    cur = 1
            return best

        h = max_consecutive(hBars) + 1  # +1 for the fixed boundaries
        v = max_consecutive(vBars) + 1
        side = min(h, v)
        return side * side
